const { withDangerousMod } = require('@expo/config-plugins');
const fs = require('fs');
const path = require('path');

// Xcode 26's Clang tightened consteval checks in a way the fmt version vendored
// by React Native doesn't satisfy (facebook/react-native#55601). A per-target
// Podfile build-setting override isn't enough: dozens of other pods include
// fmt's headers and hit the consteval check in their own compile context, so
// the macro has to be patched in the vendored header itself. This has to be a
// config plugin (not a one-off ios/Podfile edit) because ios/ is regenerated by
// `expo prebuild` on every EAS build (CNG workflow, ios/ is gitignored).
const PATCH_MARKER = '# @generated withFmtConstevalFix';
const PATCH = `
    ${PATCH_MARKER}
    fmt_header = File.join(installer.sandbox.pod_dir('fmt'), 'include', 'fmt', 'base.h')
    if File.exist?(fmt_header)
      contents = File.read(fmt_header)
      patched = contents.gsub(/#\\s*define FMT_USE_CONSTEVAL 1/, '#  define FMT_USE_CONSTEVAL 0')
      File.write(fmt_header, patched) if patched != contents
    end
`;

module.exports = function withFmtConstevalFix(config) {
  return withDangerousMod(config, [
    'ios',
    (config) => {
      const podfilePath = path.join(config.modRequest.platformProjectRoot, 'Podfile');
      let contents = fs.readFileSync(podfilePath, 'utf8');
      if (contents.includes(PATCH_MARKER)) return config;

      const postInstallMatch = contents.match(/post_install do \|installer\|\r?\n/);
      if (!postInstallMatch) {
        throw new Error('withFmtConstevalFix: could not find `post_install do |installer|` in Podfile');
      }
      const insertAt = postInstallMatch.index + postInstallMatch[0].length;
      contents = contents.slice(0, insertAt) + PATCH + contents.slice(insertAt);
      fs.writeFileSync(podfilePath, contents);
      return config;
    },
  ]);
};
